        let session = Session {
            branch_id: Some("test-branch".into()),
            messages: vec![ConversationMessage::user("hello")],
            ..Session::default()
        };
        mgr.save_branch(&session).unwrap();

        let loaded = mgr.load_branch("test-branch").unwrap();
