use std::collections::{BTreeMap, BTreeSet};
use std::sync::Arc;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
/// Permissionmode.
pub enum PermissionMode {
    Allow,
    Deny,
    Prompt,
    /// Auto-classify: read tools auto-allow, safe bash auto-allow, dangerous deny.
    Auto,
}

#[derive(Debug, Clone)]
/// Permissionrequest.
pub struct PermissionRequest {
    pub tool_name: String,
    pub input_summary: String,
}

#[derive(Debug, Clone, PartialEq, Eq)]
/// Permissionoutcome.
pub enum PermissionOutcome {
    Allow,
    Deny { reason: String },
}

/// Permissionprompter.
pub trait PermissionPrompter: Send {
    fn decide(&mut self, request: &PermissionRequest) -> PermissionOutcome;
}

#[derive(Clone)]
/// Permissionpolicy.
pub struct PermissionPolicy {
    default_mode: PermissionMode,
    tool_modes: BTreeMap<String, PermissionMode>,
    learned_allows: Arc<std::sync::Mutex<BTreeSet<String>>>,
}

impl PermissionPolicy {
    #[must_use]
    /// New.
    pub fn new(default_mode: PermissionMode) -> Self {
        Self {
            default_mode,
            tool_modes: BTreeMap::new(),
            learned_allows: Arc::new(std::sync::Mutex::new(BTreeSet::new())),
        }
    }

    #[must_use]
    /// Get default permission mode.
    pub fn mode(&self) -> PermissionMode {
        self.default_mode
    }

    /// Remember that a tool+pattern was approved (persists in session).
    pub fn learn_allow(&self, key: &str) {
        if let Ok(mut set) = self.learned_allows.lock() {
            set.insert(key.to_string());
        }
    }

    /// Check if a tool+pattern was previously approved.
    #[must_use]
    pub fn is_learned(&self, key: &str) -> bool {
        self.learned_allows
            .lock()
            .map(|s| s.contains(key))
            .unwrap_or(false)
    }

    #[must_use]
    /// With tool mode.
    pub fn with_tool_mode(mut self, tool: impl Into<String>, mode: PermissionMode) -> Self {
        self.tool_modes.insert(tool.into(), mode);
        self
    }

    #[must_use]
    /// Authorize.
    pub fn authorize(
        &self,
        tool_name: &str,
        input_summary: &str,
        prompter: Option<&mut dyn PermissionPrompter>,
    ) -> PermissionOutcome {
        let mode = self
            .tool_modes
            .get(tool_name)
            .copied()
            .unwrap_or(self.default_mode);
        match mode {
            PermissionMode::Allow => PermissionOutcome::Allow,
            PermissionMode::Deny => PermissionOutcome::Deny {
                reason: format!("tool '{tool_name}' denied by policy"),
            },
            PermissionMode::Auto => {
                // Check learned permissions first
                let learn_key = format!("{tool_name}:{}", tool_learn_key(tool_name, input_summary));
                if self.is_learned(&learn_key) {
                    return PermissionOutcome::Allow;
                }
                let result = auto_classify(tool_name, input_summary, prompter);
                if result == PermissionOutcome::Allow {
                    self.learn_allow(&learn_key);
                }
                result
            }
            PermissionMode::Prompt => {
                let learn_key = format!("{tool_name}:{}", tool_learn_key(tool_name, input_summary));
                if self.is_learned(&learn_key) {
                    return PermissionOutcome::Allow;
                }
                match prompter {
                    Some(p) => {
                        let result = p.decide(&PermissionRequest {
                            tool_name: tool_name.to_string(),
                            input_summary: input_summary.to_string(),
                        });
                        if result == PermissionOutcome::Allow {
                            self.learn_allow(&learn_key);
                        }
                        result
                    }
                    None => PermissionOutcome::Deny {
                        reason: format!("tool '{tool_name}' requires interactive approval"),
                    },
                }
            }
        }
    }
}

/// Extract a stable key for learning (first word of command for bash, tool name otherwise).
fn tool_learn_key(tool_name: &str, input: &str) -> String {
    if tool_name == "bash" {
        input.split_whitespace().next().unwrap_or("").to_string()
    } else {
        tool_name.to_string()
    }
}

/// Auto-classify tool permissions based on safety heuristics.
fn auto_classify(
    tool_name: &str,
    input_summary: &str,
    prompter: Option<&mut dyn PermissionPrompter>,
) -> PermissionOutcome {
    // Read tools: always allow
    if matches!(
        tool_name,
        "read_file"
            | "glob_search"
            | "grep_search"
            | "web_fetch"
            | "web_search"
            | "lsp_query"
            | "memory_read"
    ) {
        return PermissionOutcome::Allow;
    }
    // Write/edit in workspace: allow
    if matches!(tool_name, "write_file" | "edit_file" | "memory_write") {
        return PermissionOutcome::Allow;
    }
    // Bash: deep command classification
    if tool_name == "bash" {
        return classify_bash_command(input_summary, prompter);
    }
    // Everything else: prompt
    match prompter {
        Some(p) => p.decide(&PermissionRequest {
            tool_name: tool_name.to_string(),
            input_summary: input_summary.to_string(),
        }),
        None => PermissionOutcome::Deny {
            reason: format!("tool '{tool_name}' requires approval"),
        },
    }
}

/// Deep bash command classification with compound command support.
fn classify_bash_command(
    input: &str,
    prompter: Option<&mut dyn PermissionPrompter>,
) -> PermissionOutcome {
    let cmd = input.trim();

    // Split compound commands outside of quotes
    let parts = split_shell_commands(cmd);

    let mut needs_prompt = false;
    for part in &parts {
        match classify_single_command(part.trim()) {
            CommandRisk::Safe => {}
            CommandRisk::Dangerous(reason) => {
                return PermissionOutcome::Deny {
                    reason: format!("blocked: {reason}"),
                };
            }
            CommandRisk::NeedsReview => needs_prompt = true,
        }
    }

    if needs_prompt {
        match prompter {
            Some(p) => p.decide(&PermissionRequest {
                tool_name: "bash".into(),
                input_summary: input.to_string(),
            }),
            None => PermissionOutcome::Deny {
                reason: "bash command requires approval".into(),
            },
        }
    } else {
        PermissionOutcome::Allow
    }
}

/// Split shell command on ;, &&, || operators while respecting quotes.
fn split_shell_commands(cmd: &str) -> Vec<&str> {
    let mut parts = Vec::new();
    let mut start = 0;
    let mut in_single = false;
    let mut in_double = false;
    let bytes = cmd.as_bytes();
    let mut i = 0;
    while i < bytes.len() {
        let c = bytes[i];
        if c == b'\'' && !in_double {
            in_single = !in_single;
        } else if c == b'"' && !in_single {
            in_double = !in_double;
        } else if !in_single && !in_double {
            if c == b';' {
                parts.push(&cmd[start..i]);
                start = i + 1;
            } else if c == b'&' && i + 1 < bytes.len() && bytes[i + 1] == b'&' {
                parts.push(&cmd[start..i]);
                start = i + 2;
                i += 1;
            } else if c == b'|' && i + 1 < bytes.len() && bytes[i + 1] == b'|' {
                parts.push(&cmd[start..i]);
                start = i + 2;
                i += 1;
            } else if c == b'|' {
                parts.push(&cmd[start..i]);
                start = i + 1;
            }
        }
        i += 1;
    }
    if start < cmd.len() {
        parts.push(&cmd[start..]);
    }
    parts
}

enum CommandRisk {
    Safe,
    NeedsReview,
    Dangerous(String),
}

fn classify_single_command(cmd: &str) -> CommandRisk {
    const DANGEROUS: &[&str] = &[
        "sudo",
        "su",
        "mkfs",
        "fdisk",
        "mount",
        "umount",
        "iptables",
        "systemctl",
        "service",
        "shutdown",
        "reboot",
        "passwd",
        "useradd",
        "userdel",
    ];
    const DANGEROUS_PATTERNS: &[&str] = &[
        "rm -rf /",
        "rm -rf ~",
        "rm -rf /*",
        "> /dev/",
        "curl|sh",
        "curl|bash",
        "wget|sh",
        "wget|bash",
        "dd if=",
        "chmod 777",
        "eval $(",
        "`curl",
        "$(curl",
    ];
    const SAFE: &[&str] = &[
        "ls",
        "cat",
        "head",
        "tail",
        "wc",
        "grep",
        "rg",
        "find",
        "fd",
        "echo",
        "printf",
        "pwd",
        "env",
        "which",
        "type",
        "date",
        "whoami",
        "hostname",
        "uname",
        "file",
        "stat",
        "diff",
        "sort",
        "uniq",
        "tr",
        "cut",
        "awk",
        "sed",
        "jq",
        "tree",
        "du",
        "df",
        "free",
        "top",
        "ps",
        "lsof",
        "pgrep",
        "git status",
        "git log",
        "git diff",
        "git show",
        "git branch",
        "git remote",
        "git tag",
        "git stash list",
        "git blame",
    ];
    const BUILD_SAFE: &[&str] = &[
        "cargo test",
        "cargo build",
        "cargo check",
        "cargo clippy",
        "cargo fmt",
        "cargo run",
        "cargo doc",
        "cargo bench",
        "npm test",
        "npm run",
        "npm install",
        "npm ci",
        "npx",
        "yarn test",
        "yarn build",
        "yarn install",
        "pnpm test",
        "pnpm run",
        "pnpm install",
        "python",
        "python3",
        "pytest",
        "pip install",
        "go test",
        "go build",
        "go run",
        "go vet",
        "make",
        "cmake",
        "gradle",
        "mvn",
        "node",
        "deno",
        "bun",
        "rustc",
        "gcc",
        "g++",
        "clang",
    ];
    const GIT_WRITE_SAFE: &[&str] = &[
        "git add",
        "git commit",
        "git push",
        "git pull",
        "git fetch",
        "git checkout",
        "git switch",
        "git merge",
        "git rebase",
        "git stash",
        "git cherry-pick",
        "git reset",
    ];

    let first_word = cmd.split_whitespace().next().unwrap_or("");

    if DANGEROUS.contains(&first_word) {
        return CommandRisk::Dangerous(format!("{first_word} blocked"));
    }
    for pat in DANGEROUS_PATTERNS {
        if cmd.contains(pat) {
            return CommandRisk::Dangerous(format!("dangerous: {pat}"));
        }
    }
    if SAFE.iter().any(|s| cmd.starts_with(s)) {
        return CommandRisk::Safe;
    }
    if BUILD_SAFE.iter().any(|s| cmd.starts_with(s)) {
        return CommandRisk::Safe;
    }
    if GIT_WRITE_SAFE.iter().any(|s| cmd.starts_with(s)) {
        return CommandRisk::Safe;
    }
    CommandRisk::NeedsReview
}

#[cfg(test)]
mod tests {
    use super::*;

    struct AllowAll;
    impl PermissionPrompter for AllowAll {
        fn decide(&mut self, _: &PermissionRequest) -> PermissionOutcome {
            PermissionOutcome::Allow
        }
    }

    #[test]
    fn allow_mode_passes() {
        let policy = PermissionPolicy::new(PermissionMode::Allow);
        assert_eq!(
            policy.authorize("bash", "ls", None),
            PermissionOutcome::Allow
        );
    }

    #[test]
    fn deny_mode_blocks() {
        let policy = PermissionPolicy::new(PermissionMode::Deny);
        assert!(matches!(
            policy.authorize("bash", "rm -rf", None),
            PermissionOutcome::Deny { .. }
        ));
    }

    #[test]
    fn prompt_mode_delegates() {
        let policy = PermissionPolicy::new(PermissionMode::Prompt);
        assert_eq!(
            policy.authorize("bash", "ls", Some(&mut AllowAll)),
            PermissionOutcome::Allow
        );
    }

    #[test]
    fn tool_override() {
        let policy = PermissionPolicy::new(PermissionMode::Allow)
            .with_tool_mode("bash", PermissionMode::Deny);
        assert!(matches!(
            policy.authorize("bash", "ls", None),
            PermissionOutcome::Deny { .. }
        ));
        assert_eq!(
            policy.authorize("read_file", "x", None),
            PermissionOutcome::Allow
        );
    }

    #[test]
    fn learned_permission_auto_allows() {
        let policy = PermissionPolicy::new(PermissionMode::Auto);
        // First call with prompter — gets auto-classified
        let result = policy.authorize("bash", "cargo test", Some(&mut AllowAll));
        assert_eq!(result, PermissionOutcome::Allow);
        // Second call without prompter — learned, auto-allowed
        let result2 = policy.authorize("bash", "cargo build", None);
        // Same first-word "cargo" → learned
        assert_eq!(result2, PermissionOutcome::Allow);
    }

    #[test]
    fn learned_permission_prompt_mode() {
        let policy = PermissionPolicy::new(PermissionMode::Prompt);
        // First call needs prompter
        let r = policy.authorize("bash", "make build", Some(&mut AllowAll));
        assert_eq!(r, PermissionOutcome::Allow);
        // Now learned — no prompter needed
        let r2 = policy.authorize("bash", "make test", None);
        assert_eq!(r2, PermissionOutcome::Allow);
    }

    #[test]
    fn learn_allow_and_is_learned() {
        let policy = PermissionPolicy::new(PermissionMode::Allow);
        assert!(!policy.is_learned("test:key"));
        policy.learn_allow("test:key");
        assert!(policy.is_learned("test:key"));
    }
}

use std::path::{Path, PathBuf};
use std::time::Duration;

use tokio::process::Command;

use crate::error::ToolError;
use crate::spec::ToolSpec;

/// Discovers user-defined script tools from `.magic-code/tools/*.sh`.
/// Each script becomes a tool named after the file (without extension).
/// Scripts receive JSON input via stdin and should print output to stdout.
#[must_use]
/// Discover plugins.
pub fn discover_plugins(workspace: &Path) -> Vec<ToolSpec> {
    let dir = workspace.join(".magic-code/tools");
    let Ok(entries) = std::fs::read_dir(&dir) else {
        return Vec::new();
    };
    entries
        .flatten()
        .filter(|e| {
            e.path()
                .extension()
                .is_some_and(|ext| ext == "sh" || ext == "py" || ext == "js")
        })
        .filter_map(|e| {
            let name = e.path().file_stem()?.to_string_lossy().to_string();
            let desc = read_plugin_description(&e.path());
            Some(ToolSpec {
                name: format!("plugin_{name}"),
                description: desc,
                input_schema: serde_json::json!({
                    "type": "object",
                    "properties": {
                        "input": { "type": "string", "description": "Input for the plugin script" }
                    },
                    "required": ["input"]
                }),
            })
        })
        .collect()
}

/// Execute a plugin script. Passes input via stdin, captures stdout.
/// Execute a user plugin script from `.magic-code/tools/`.
pub async fn execute_plugin(
    workspace: &Path,
    plugin_name: &str,
    input: &str,
) -> Result<String, ToolError> {
    let name = plugin_name.strip_prefix("plugin_").unwrap_or(plugin_name);
    let script = find_plugin_script(workspace, name)
        .ok_or_else(|| ToolError::NotFound(format!("plugin script not found: {name}")))?;

    let interpreter = if script.extension().is_some_and(|e| e == "py") {
        "python3"
    } else if script.extension().is_some_and(|e| e == "js") {
        "node"
    } else {
        "sh"
    };

    let output = tokio::time::timeout(Duration::from_secs(60), async {
        Command::new(interpreter)
            .arg(&script)
            .env("PLUGIN_INPUT", input)
            .output()
            .await
            .map_err(ToolError::Io)
    })
    .await
    .map_err(|_| ToolError::Timeout(60_000))??;

    let stdout = String::from_utf8_lossy(&output.stdout);
    let stderr = String::from_utf8_lossy(&output.stderr);
    if output.status.success() {
        Ok(stdout.to_string())
    } else {
        Ok(format!("{stdout}\nSTDERR: {stderr}"))
    }
}

fn find_plugin_script(workspace: &Path, name: &str) -> Option<PathBuf> {
    let dir = workspace.join(".magic-code/tools");
    for ext in ["sh", "py", "js"] {
        let path = dir.join(format!("{name}.{ext}"));
        if path.exists() {
            return Some(path);
        }
    }
    None
}

/// Read first line comment as description (e.g. `# Description: my tool`).
fn read_plugin_description(path: &Path) -> String {
    std::fs::read_to_string(path)
        .ok()
        .and_then(|content| {
            content.lines().find_map(|line| {
                line.strip_prefix("# ")
                    .or_else(|| line.strip_prefix("// "))
                    .map(String::from)
            })
        })
        .unwrap_or_else(|| format!("User plugin: {}", path.display()))
}

